// <model-viewer> vendor placeholder.
//
// STUB. The real bundle (Google's model-viewer web component, ~300 KB)
// registers a custom element <model-viewer> that renders glTF/GLB meshes.
// This placeholder registers a no-op custom element so the SPA's mesh
// widget can attach attributes without throwing, and emits a console.warn.
// Replace with the upstream bundle (see README.md) to enable 3D rendering.

(function () {
  if (typeof window === 'undefined') return;
  if (window.__topoModelViewerPlaceholder) return;
  window.__topoModelViewerPlaceholder = true;
  if (typeof console !== 'undefined' && console.warn) {
    console.warn(
      '[topo-debug] model-viewer.min.js is a placeholder. Drop the real ' +
      '@google/model-viewer bundle at ' +
      'topo-core/lib/Debug/Server/vendor/model-viewer.min.js to enable ' +
      'glTF mesh rendering. See README.md in the same directory.'
    );
  }
  try {
    if (window.customElements &&
        !window.customElements.get('model-viewer')) {
      class TopoModelViewerStub extends HTMLElement {
        connectedCallback() {
          this.style.display = 'block';
          this.style.minHeight = '120px';
          this.textContent =
            '[model-viewer placeholder — drop the real bundle to render ' +
            (this.getAttribute('src') || 'the glTF') + ']';
        }
      }
      window.customElements.define('model-viewer', TopoModelViewerStub);
    }
  } catch (_) { /* custom elements unavailable — non-fatal */ }
})();
